-- Toronto ward workload context: real City Wards polygons + real Toronto 311
-- ward workload counts.
--
-- This migration replaces the synthetic Brampton ward workload overlay with REAL
-- Toronto data for the authenticated "Toronto ward workload context" page:
--
--   1. public.toronto_ward_boundaries — the 25 City of Toronto wards (current
--      25-ward model) from City of Toronto Open Data "City Wards" (EPSG:4326
--      GeoJSON). These are REAL Toronto ward polygons, used purely as the
--      geographic base layer of the workload map.
--
--   2. public.v_toronto_ward_workload — REAL Toronto 311 benchmark complaint
--      volume aggregated per ward from public.municipal_complaints. The 311
--      ward_or_area values join to the City Wards polygons by ward number
--      (e.g. "Toronto-Danforth (14)" -> ward 14), a join the EDA confirmed at
--      100%. This is Toronto 311 benchmark data — decision support only, not
--      Brampton operational complaint data, and never a final enforcement
--      decision.
--
-- Note: this is Toronto geography and Toronto 311 volume. It must NEVER be
-- plotted onto Brampton wards. The Brampton ward boundaries remain only as a
-- future local-context layer.
--
-- SELECT is restricted to the authenticated role, matching the rest of the
-- schema.

create table if not exists public.toronto_ward_boundaries (
  id              bigserial primary key,
  area_short_code integer not null unique,
  ward_name       text not null,
  ward_desc       text not null,
  source_city     text not null default 'Toronto',
  source_dataset  text not null default 'City of Toronto Open Data - City Wards (25-ward model)',
  geojson_geometry jsonb not null,
  created_at      timestamptz not null default now()
);

comment on table public.toronto_ward_boundaries is
  'City of Toronto 25-ward boundaries (City Wards open data, EPSG:4326). Real Toronto ward polygons used as the geographic base layer for the Toronto ward workload context map. Not Brampton geography.';

truncate table public.toronto_ward_boundaries restart identity;

insert into public.toronto_ward_boundaries
  (area_short_code, ward_name, ward_desc, geojson_geometry)
