alter table public.toronto_ward_boundaries enable row level security;

drop policy if exists "Authenticated users can read Toronto ward boundaries"
  on public.toronto_ward_boundaries;

create policy "Authenticated users can read Toronto ward boundaries"
  on public.toronto_ward_boundaries
  for select
  to authenticated
  using (true);

grant select on public.toronto_ward_boundaries to authenticated;

-- ---------------------------------------------------------------------------
-- Real Toronto 311 ward workload counts
-- ---------------------------------------------------------------------------
-- Aggregates actual benchmark complaint volume per Toronto ward from
-- public.municipal_complaints. Only rows whose ward_or_area carries a trailing
-- ward number (e.g. "(14)") are kept, so non-ward buckets like "Unknown" are
-- excluded. ward_number is the join key to toronto_ward_boundaries.area_short_code.

create or replace view public.v_toronto_ward_workload as
select
  ward_or_area,
  (regexp_replace(ward_or_area, '^.*\((\d+)\)\s*$', '\1'))::int as ward_number,
  count(*)                                                            as complaint_volume,
  -- Disjoint buckets: open (new / awaiting), in progress, and closed.
  count(*) filter (where status is null
    or status not in ('In Progress', 'Closed', 'Completed', 'Cancelled')) as open_cases,
  count(*) filter (where status = 'In Progress')                     as in_progress_cases,
  count(*) filter (where status in ('Closed', 'Completed'))          as closed_cases,
  mode() within group (order by complaint_type)                      as top_category
from public.municipal_complaints
where ward_or_area is not null
  and ward_or_area ~ '\(\d+\)\s*$'
group by ward_or_area
order by complaint_volume desc;

comment on view public.v_toronto_ward_workload is
  'Real Toronto 311 benchmark complaint volume per Toronto ward, aggregated from public.municipal_complaints and joined to toronto_ward_boundaries by ward number. Decision support only - not Brampton operational data, not a final enforcement decision.';

grant select on public.v_toronto_ward_workload to authenticated;
